/*
999911659 是一个质数
\phi(999911659)=999911658=2*3*4679*35617
*/
#include <bits/stdc++.h>
using namespace std;

int n,g,a[4],m[4]={2,3,4679,35617},fac[4][36010],inv[4][36010];

int quick_mi(int a,int b,int p){
    long long ans=1,base=a;
    while(b){
        if(b&1)
            ans=ans*base%p;
        base=base*base%p,b>>=1;
    }
    return ans;
}

int C(int a,int b,int p){
    if(a<0 || a<b)
        return 0;
    return 1LL*fac[p][a]*inv[p][a-b]%m[p]*inv[p][b]%m[p];
}

int Lucas(int a,int b,int p){
    int res=1;
    while((a || b) && res)
        res=1LL*res*C(a%m[p],b%m[p],p)%m[p],a/=m[p],b/=m[p];
    return res;
}

int exgcd(int a,int b,long long &x,long long &y){
    if(b==0){
        x=1,y=0;
        return a;
    }
    int gcd=exgcd(b,a%b,x,y),z=x;
    x=y,y=z-(a/b)*y;
    return gcd;
}

int cal(int a,int b){
    long long x,y;
    exgcd(a,b,x,y);
    return x%b;
}

int main(){
    for(int i=0;i<4;i++){
        fac[i][0]=1;
        for(int j=1;j<m[i];j++)
            fac[i][j]=1LL*fac[i][j-1]*j%m[i];
        inv[i][m[i]-1]=quick_mi(fac[i][m[i]-1],m[i]-2,m[i]);
        for(int j=m[i]-2;j>=0;j--)
            inv[i][j]=1LL*inv[i][j+1]*(j+1)%m[i];
    }
    scanf("%d%d",&n,&g);
    if(g==999911659){
        printf("0");
        return 0;
    }
    g%=999911659;
    for(int i=1;i*i<=n;i++)
        if(n%i==0){
            for(int j=0;j<4;j++){
                a[j]=(a[j]+Lucas(n,i,j))%m[j];
                if(i*i<n)
                    a[j]=(a[j]+Lucas(n,n/i,j))%m[j];
            }
        }
    int ans=0,M=999911658;
    for(int i=0;i<4;i++)
        ans=(ans+1LL*(M/m[i])*a[i]%M*cal(M/m[i],m[i])%M)%M;
    printf("%d",quick_mi(g,(ans+M)%M,M+1));
    return 0;
}
